  1→/**
  2→ * Acceptance Test Kit — Shared Infrastructure
  3→ *
  4→ * Boots an in-process Brain server with isolated SurrealDB namespace.
  5→ * All acceptance test suites (core, orchestrator, intent, coding-session, etc.)
  6→ * build on this shared setup.
  7→ */
  8→import { afterAll, beforeAll } from "bun:test";
  9→import { randomBytes, createHash } from "node:crypto";
 10→import { readFileSync } from "node:fs";
 11→import { join } from "node:path";
 12→import { RecordId, Surreal } from "surrealdb";
 13→import * as jose from "jose";
 14→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
 15→import { createBrainServer } from "../../app/src/server/runtime/start-server";
 16→import { createRuntimeDependencies } from "../../app/src/server/runtime/dependencies";
 17→import { createSseRegistry } from "../../app/src/server/streaming/sse-registry";
 18→import { createInflightTracker } from "../../app/src/server/runtime/types";
 19→import { createNonceCache } from "../../app/src/server/oauth/nonce-cache";
 20→import { createLiveSelectManager } from "../../app/src/server/reactive/live-select-manager";
 21→import { createFeedSseBridge } from "../../app/src/server/reactive/feed-sse-bridge";
 22→// Agent activator + loop dampener are created inside createBrainServer
 23→import type { ServerConfig } from "../../app/src/server/runtime/config";
 24→import type { ServerDependencies, InflightTracker } from "../../app/src/server/runtime/types";
 25→import { createMcpClientFactory } from "../../app/src/server/tool-registry/mcp-client";
 26→
 27→// ── Shared AI dependencies for standalone acceptance tests ──
 28→
 29→const openrouter = createOpenRouter({ apiKey: requireTestEnv("OPENROUTER_API_KEY") });
 30→
 31→export const testAI = {
 32→  openrouter,
 33→  extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
 34→  extractionModel: openrouter(requireTestEnv("EXTRACTION_MODEL")),
 35→  embeddingModel: openrouter.textEmbeddingModel(requireTestEnv("EMBEDDING_MODEL")),
 36→  embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
 37→};
 38→
 39→/** @deprecated Use `testAI` instead. */
 40→export const smokeAI = testAI;
 41→
 42→export type AcceptanceTestRuntime = {
 43→  baseUrl: string;
 44→  surreal: Surreal;
 45→  namespace: string;
 46→  database: string;
 47→  port: number;
 48→};
 49→
 50→/** @deprecated Use `AcceptanceTestRuntime` instead. */
 51→export type SmokeTestRuntime = AcceptanceTestRuntime;
 52→
 53→export type AcceptanceSuiteOptions = {
 54→  /** Direct config overrides — applied to the ServerConfig object without touching process.env. */
 55→  configOverrides?: Partial<ServerConfig>;
 56→  /** Override mcpClientFactory for tests needing mock MCP servers. */
 57→  mcpClientFactoryOverride?: ServerDependencies["mcpClientFactory"];
 58→};
 59→
 60→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 61→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 62→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 63→
 64→/**
 65→ * Split SQL into statements respecting `{...}` block nesting.
 66→ * DEFINE FUNCTION / DEFINE EVENT bodies contain semicolons that are NOT
 67→ * statement terminators. Naively splitting on `;` breaks those bodies into
 68→ * orphaned fragments that corrupt the batch query.
 69→ */
 70→function splitSqlStatements(sql: string): string[] {
 71→  const stmts: string[] = [];
 72→  let current = "";
 73→  let depth = 0;
 74→  for (let i = 0; i < sql.length; i++) {
 75→    const ch = sql[i];
 76→    if (ch === "{") depth++;
 77→    else if (ch === "}") depth--;
 78→
 79→    if (ch === ";" && depth === 0) {
 80→      const trimmed = current.trim();
 81→      if (trimmed.length > 0) stmts.push(trimmed);
 82→      current = "";
 83→    } else {
 84→      current += ch;
 85→    }
 86→  }
 87→  const trimmed = current.trim();
 88→  if (trimmed.length > 0) stmts.push(trimmed);
 89→  return stmts;
 90→}
 91→
 92→/**
 93→ * Apply the base schema to a SurrealDB instance.
 94→ *
 95→ * DEFINE ANALYZER cannot run inside a transaction in SurrealDB v3.0+.
 96→ * The SDK may treat a multi-statement .query() as an implicit transaction,
 97→ * causing the analyzer and dependent FULLTEXT indexes to fail silently.
 98→ *
 99→ * We split the schema into three phases:
100→ * 1. DEFINE ANALYZER (must run outside any transaction)
101→ * 2. Schema definitions (DEFINE TABLE/FIELD/INDEX) — batch is fine
102→ * 3. Seed data (CREATE statements) — separate batch to isolate from index errors
103→ */
104→export async function applyTestSchema(surreal: Surreal): Promise<void> {
105→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
106→
107→  // Strip full-line comments before splitting — comments may contain semicolons
108→  // (e.g. "-- The edge is the source of truth; status is a derived consequence.")
109→  // which would create spurious fragments after the split.
110→  const withoutComments = schemaSql
111→    .split("\n")
112→    .filter((line) => !line.trimStart().startsWith("--"))
113→    .join("\n");
114→
115→  // Brace-aware split: only split on `;` outside `{...}` blocks.
116→  // DEFINE FUNCTION and DEFINE EVENT bodies contain semicolons that must not
117→  // be treated as statement terminators.
118→  const statements = splitSqlStatements(withoutComments);
119→
120→  // Phase 1: DEFINE ANALYZER (must be isolated)
121→  const analyzerStmts = statements.filter((s) => s.startsWith("DEFINE ANALYZER"));
122→  for (const stmt of analyzerStmts) {
123→    await surreal.query(stmt + ";");
124→  }
125→
126→  // Phase 2: Schema definitions (DEFINE TABLE/FIELD/INDEX/FUNCTION/EVENT)
127→  const schemaStmts = statements.filter(
128→    (s) => !s.startsWith("DEFINE ANALYZER") && !s.startsWith("CREATE"),
129→  );
130→  if (schemaStmts.length > 0) {
131→    await surreal.query(schemaStmts.map((s) => s + ";").join("\n"));
132→  }
133→
134→  // Phase 3: Seed data (CREATE statements) — isolated so index issues don't block seeds
135→  const seedStmts = statements.filter((s) => s.startsWith("CREATE"));
136→  if (seedStmts.length > 0) {
137→    await surreal.query(seedStmts.map((s) => s + ";").join("\n"));
138→  }
139→}
140→
141→export function setupAcceptanceSuite(
142→  suiteName: string,
143→  options?: AcceptanceSuiteOptions,
144→): () => AcceptanceTestRuntime {
145→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
146→  const namespace = `accept_${runId}`;
147→  const suiteSlug = suiteName
148→    .toLowerCase()
149→    .replace(/[^a-z0-9]+/g, "_")
150→    .replace(/^_+|_+$/g, "");
151→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
152→
153→  let runtime: AcceptanceTestRuntime | undefined;
154→  let server: ReturnType<typeof Bun.serve> | undefined;
155→  let runtimeSurreal: Surreal | undefined;
156→  let analyticsSurreal: Surreal | undefined;
157→  let inflight: InflightTracker | undefined;
158→  let setupSucceeded = false;
159→
160→  beforeAll(async () => {
161→    const surreal = new Surreal();
162→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
163→    await withTimeout(
164→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
165→      10_000,
166→      "authenticate with SurrealDB",
167→    );
168→
169→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
170→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
171→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
172→    await withTimeout(
173→      () => surreal.use({ namespace, database }),
174→      10_000,
175→      "switch to test namespace/database",
176→    );
177→
178→    await withTimeout(() => applyTestSchema(surreal), 20_000, "apply schema");
179→
180→    // Reserve a port so betterAuth gets the real URL at init time
181→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
182→    const reservedPort = tempServer.port;
183→    tempServer.stop(true);
184→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
185→
186→    const config: ServerConfig = {
187→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
188→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
189→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
190→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
191→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
192→      embeddingModelId: requireTestEnv("EMBEDDING_MODEL"),
193→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
194→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
195→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
196→      surrealUrl,
197→      surrealUsername,
198→      surrealPassword,
199→      surrealNamespace: namespace,
200→      surrealDatabase: database,
201→      port: reservedPort,
202→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
203→      betterAuthUrl: baseUrl,
204→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
205→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
206→      observerModelId: process.env.OBSERVER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
207→      scorerModelId: process.env.SCORER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
208→      anthropicApiUrl: process.env.ANTHROPIC_API_URL?.trim() || "https://api.anthropic.com",
209→      ...(process.env.ANTHROPIC_API_KEY?.trim() ? { anthropicApiKey: process.env.ANTHROPIC_API_KEY.trim() } : {}),
210→      inferenceProvider: "openrouter",
211→      selfHosted: false,
212→      worktreeManagerEnabled: false,
213→      ...options?.configOverrides,
214→    };
215→
216→    const deps = await createRuntimeDependencies(config);
217→    runtimeSurreal = deps.surreal;
218→    analyticsSurreal = deps.analyticsSurreal;
219→    inflight = createInflightTracker();
220→
221→    const serverDeps: ServerDependencies = {
222→      config,
223→      surreal: deps.surreal,
224→      analyticsSurreal: deps.analyticsSurreal,
225→      auth: deps.auth,
226→      chatAgentModel: deps.chatAgentModel,
227→      extractionModel: deps.extractionModel,
228→      pmAgentModel: deps.pmAgentModel,
229→      analyticsAgentModel: deps.analyticsAgentModel,
230→      embeddingModel: deps.embeddingModel,
231→      observerModel: deps.observerModel,
232→      scorerModel: deps.scorerModel,
233→      sse: createSseRegistry(),
234→      inflight,
235→      asSigningKey: deps.asSigningKey,
236→      nonceCache: createNonceCache(),
237→      mcpClientFactory: options?.mcpClientFactoryOverride ?? createMcpClientFactory(),
238→    };
239→
240→    server = createBrainServer(serverDeps);
241→    const port = server.port;
242→
243→    // Start reactive coordination layer: LIVE SELECT -> Feed SSE Bridge -> SSE Registry
244→    const liveSelectManager = createLiveSelectManager({ surreal: deps.surreal });
245→    const feedSseBridge = createFeedSseBridge({
246→      liveSelectManager,
247→      sseRegistry: serverDeps.sse,
248→    });
249→    feedSseBridge.subscribeAll();
250→
251→    // Agent Coordinator is created inside createBrainServer (called above).
252→    // In prod, DEFINE EVENT webhooks call the coordinator endpoint.
253→    // In acceptance tests, observations trigger the coordinator via the same HTTP endpoint.
254→
255→    inflight.track(
256→      liveSelectManager.start().catch(() => undefined),
257→    );
258→
259→    runtime = { baseUrl, surreal, namespace, database, port };
260→    setupSucceeded = true;
261→  }, 60_000);
262→
263→  afterAll(async () => {
264→    // Drain fire-and-forget work (e.g. webhook extraction) before closing DB
265→    if (inflight) {
266→      await inflight.drain(15_000);
267→    }
268→
269→    if (server) {
270→      server.stop(true);
271→    }
272→
273→    if (runtimeSurreal) {
274→      await runtimeSurreal.close().catch(() => undefined);
275→    }
276→    if (analyticsSurreal) {
277→      await analyticsSurreal.close().catch(() => undefined);
278→    }
279→
280→    if (!runtime) {
281→      return;
282→    }
283→
284→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
285→      try {
286→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
287→      } catch {
288→        // Best effort cleanup.
289→      }
290→
291→      try {
292→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
293→      } catch {
294→        // Best effort cleanup.
295→      }
296→    }
297→
298→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
299→  }, 20_000);
300→
301→  return () => {
302→    if (!runtime) {
303→      throw new Error("Acceptance runtime requested before suite setup completed");
304→    }
305→    return runtime;
306→  };
307→}
308→
309→/** @deprecated Use `setupAcceptanceSuite` instead. */
310→export const setupSmokeSuite = setupAcceptanceSuite;
311→
312→// ---------------------------------------------------------------------------
313→// Auth Helpers
314→// ---------------------------------------------------------------------------
315→
316→export type TestUser = {
317→  headers: Record<string, string>;
318→};
319→
320→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
321→  const email = `test-${Date.now()}-${suffix}@test.local`;
322→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
323→    method: "POST",
324→    headers: { "Content-Type": "application/json" },
325→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
326→    redirect: "manual",
327→  });
328→
329→  if (!response.ok) {
330→    const body = await response.text();
331→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
332→  }
333→
334→  const setCookie = response.headers.getSetCookie();
335→  if (!setCookie || setCookie.length === 0) {
336→    throw new Error("Sign-up did not return session cookies");
337→  }
338→
339→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
340→  return { headers: { Cookie: cookieHeader } };
341→}
342→
343→// ---------------------------------------------------------------------------
344→// SSE Helpers
345→// ---------------------------------------------------------------------------
346→
347→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
348→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
349→  if (!response.ok || !response.body) {
350→    throw new Error(`Failed to open SSE stream (${response.status})`);
351→  }
352→
353→  const reader = response.body.getReader();
354→  const decoder = new TextDecoder();
355→  const events: T[] = [];
356→  let buffer = "";
357→
358→  const timeout = setTimeout(() => {
359→    void reader.cancel();
360→  }, timeoutMs);
361→
362→  try {
363→    while (true) {
364→      const { value, done } = await reader.read();
365→      if (done) {
366→        break;
367→      }
368→
369→      buffer += decoder.decode(value, { stream: true });
370→      const segments = buffer.split("\n\n");
371→      buffer = segments.pop() ?? "";
372→
373→      for (const segment of segments) {
374→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
375→        if (!dataLine) {
376→          continue;
377→        }
378→
379→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
380→        events.push(event);
381→
382→        if (event.type === "error") {
383→          const errorText = (event as { error?: string }).error;
384→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
385→        }
386→
387→        if (event.type === "done") {
388→          return events;
389→        }
390→      }
391→    }
392→  } finally {
393→    clearTimeout(timeout);
394→    reader.releaseLock();
395→  }
396→
397→  return events;
398→}
399→
400→// ---------------------------------------------------------------------------
401→// HTTP Helpers
402→// ---------------------------------------------------------------------------
403→
404→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
405→  const response = await fetch(url, init);
406→  if (!response.ok) {
407→    const body = await response.text();
408→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
409→  }
410→
411→  return (await response.json()) as T;
412→}
413→
414→export async function fetchRaw(url: string, init?: RequestInit): Promise<Response> {
415→  return fetch(url, init);
416→}
417→
418→// ---------------------------------------------------------------------------
419→// OAuth Helpers
420→// ---------------------------------------------------------------------------
421→
422→function base64url(buf: Buffer): string {
423→  return buf.toString("base64url");
424→}
425→
426→function generatePkce(): { verifier: string; challenge: string } {
427→  const verifier = base64url(randomBytes(32));
428→  const challenge = base64url(createHash("sha256").update(verifier).digest());
429→  return { verifier, challenge };
430→}
431→
432→/**
433→ * Obtain an OAuth2 JWT access token for MCP endpoints.
434→ * Requires a SurrealDB connection to skip consent screen.
435→ */
436→export async function getOAuthToken(
437→  baseUrl: string,
438→  surreal: Surreal,
439→  sessionHeaders: Record<string, string>,
440→  scopes: string = "graph:read graph:reason session:write offline_access",
441→): Promise<string> {
442→  // Trigger JWKS key generation if not yet done
443→  await fetch(`${baseUrl}/api/auth/jwks`);
444→
445→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
446→    method: "POST",
447→    headers: { "Content-Type": "application/json" },
448→    body: JSON.stringify({
449→      client_name: `test-client-${Date.now()}`,
450→      redirect_uris: ["http://127.0.0.1:9999/callback"],
451→      grant_types: ["authorization_code", "refresh_token"],
452→      response_types: ["code"],
453→      token_endpoint_auth_method: "none",
454→    }),
455→  });
456→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
457→
458→  const { client_id } = (await dcrRes.json()) as { client_id: string };
459→
460→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
461→    cid: client_id,
462→  });
463→
464→  const { verifier, challenge } = generatePkce();
465→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
466→  authUrl.searchParams.set("client_id", client_id);
467→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
468→  authUrl.searchParams.set("response_type", "code");
469→  authUrl.searchParams.set("scope", scopes);
470→  authUrl.searchParams.set("state", "test-state");
471→  authUrl.searchParams.set("code_challenge", challenge);
472→  authUrl.searchParams.set("code_challenge_method", "S256");
473→  authUrl.searchParams.set("resource", baseUrl);
474→
475→  const authRes = await fetch(authUrl.toString(), {
476→    headers: sessionHeaders,
477→    redirect: "manual",
478→  });
479→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
480→
481→  const location = authRes.headers.get("location")!;
482→  const redirectUrl = new URL(location, baseUrl);
483→  const code = redirectUrl.searchParams.get("code") ?? "";
484→  if (!code) throw new Error(`No code in redirect: ${location}`);
485→
486→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
487→    method: "POST",
488→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
489→    body: new URLSearchParams({
490→      grant_type: "authorization_code",
491→      code,
492→      redirect_uri: "http://127.0.0.1:9999/callback",
493→      client_id,
494→      code_verifier: verifier,
495→      resource: baseUrl,
496→    }),
497→  });
498→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
499→
500→  const tokens = (await tokenRes.json()) as { access_token: string };
501→  return tokens.access_token;
502→}
