526→export async function createTestUserWithMcp(
527→  baseUrl: string,
528→  surreal: Surreal,
529→  suffix: string,
530→  options?: { workspaceId?: string },
531→): Promise<TestUserWithMcp> {
532→  const user = await createTestUser(baseUrl, suffix);
533→
534→  // Generate DPoP key pair
535→  const keyPair = await generateDPoPKeyPair();
536→
537→  // Use provided workspace or create a new one for this test identity
538→  const workspaceId = options?.workspaceId ?? `test-workspace-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
539→  const workspaceRecord = new RecordId("workspace", workspaceId);
540→  if (!options?.workspaceId) {
541→    await surreal.query(`CREATE $workspace CONTENT $content;`, {
542→      workspace: workspaceRecord,
543→      content: {
544→        name: `Test Workspace ${suffix}`,
545→        status: "active",
546→        onboarding_complete: true,
547→        onboarding_turn_count: 0,
548→        onboarding_summary_pending: false,
