555→  // Create identity record for this user
556→  const identityId = `test-identity-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
557→  const identityRecord = new RecordId("identity", identityId);
558→
559→  await surreal.query(`CREATE $identity CONTENT $content;`, {
