584→    { type: "brain_action", action: "read", resource: "entity" },
585→    { type: "brain_action", action: "read", resource: "suggestion" },
586→    { type: "brain_action", action: "read", resource: "intent" },
587→    { type: "brain_action", action: "reason", resource: "decision" },
588→    { type: "brain_action", action: "reason", resource: "constraint" },
589→    { type: "brain_action", action: "reason", resource: "commit" },
590→    { type: "brain_action", action: "create", resource: "decision" },
591→    { type: "brain_action", action: "create", resource: "question" },
592→    { type: "brain_action", action: "create", resource: "task" },
593→    { type: "brain_action", action: "create", resource: "note" },
594→    { type: "brain_action", action: "create", resource: "observation" },
595→    { type: "brain_action", action: "create", resource: "suggestion" },
596→    { type: "brain_action", action: "create", resource: "session" },
597→    { type: "brain_action", action: "create", resource: "commit" },
598→    { type: "brain_action", action: "create", resource: "intent" },
599→    { type: "brain_action", action: "update", resource: "task" },
