603→  ];
604→
605→  const intentId = `test-intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
606→  const intentRecord = new RecordId("intent", intentId);
607→  const traceRecord = new RecordId("trace", `trace-${intentId}`);
608→
609→  await surreal.query(`CREATE $trace CONTENT $traceContent;`, {
610→    trace: traceRecord,
611→    traceContent: { type: "intent_submission", actor: identityRecord, workspace: workspaceRecord, created_at: new Date() },
612→  });
613→
614→  await surreal.query(`CREATE $intent CONTENT $content;`, {
615→    intent: intentRecord,
616→    content: {
617→      goal: "Broad test access",
618→      reasoning: "Pre-authorized for acceptance testing",
619→      status: "authorized",
620→      priority: 50,
621→      authorization_details: broadActions,
622→      dpop_jwk_thumbprint: keyPair.thumbprint,
623→      action_spec: { provider: "test", action: "broad_access", params: {} },
624→      trace_id: traceRecord,
