637→
638→  // Request DPoP-bound access token from Custom AS
639→  const tokenUri = `${baseUrl}/api/auth/token`;
640→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
641→
642→  const tokenRes = await fetch(tokenUri, {
643→    method: "POST",
644→    headers: {
645→      "Content-Type": "application/json",
646→      DPoP: dpopProof,
647→    },
648→    body: JSON.stringify({
649→      grant_type: "urn:brain:intent-authorization",
650→      intent_id: intentId,
651→      authorization_details: broadActions,
652→    }),
653→  });
654→
655→  if (!tokenRes.ok) {
656→    const body = await tokenRes.text();
657→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
658→  }
659→
660→  const { access_token } = (await tokenRes.json()) as { access_token: string };
661→
662→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
663→    const method = options?.method ?? "POST";
664→    const requestUri = `${baseUrl}${path}`;
665→    const proof = await createDPoPProof(keyPair, method, requestUri);
666→
667→    return fetch(requestUri, {
668→      method,
669→      headers: {
670→        "Content-Type": "application/json",
671→        Authorization: `DPoP ${access_token}`,
672→        DPoP: proof,
673→      },
674→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
675→    });
676→  };
677→
678→  return {
679→    ...user,
680→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
681→    mcpFetch,
682→    accessToken: access_token,
683→    keyPair,
684→    workspaceId,
685→    identityId,
686→  };
687→}
