689→// ---------------------------------------------------------------------------
690→// DPoP Helpers
691→// ---------------------------------------------------------------------------
692→
693→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
694→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
695→    { name: "ECDSA", namedCurve: "P-256" },
696→    true,
697→    ["sign", "verify"],
698→  );
699→
700→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
701→  const thumbprint = await computeDPoPThumbprint(publicJwk);
702→
703→  return { privateKey, publicKey, publicJwk, thumbprint };
704→}
705→
706→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
707→  const thumbprintInput = JSON.stringify({
708→    crv: publicJwk.crv,
709→    kty: publicJwk.kty,
710→    x: publicJwk.x,
711→    y: publicJwk.y,
712→  });
713→
714→  const hashBuffer = await crypto.subtle.digest(
715→    "SHA-256",
716→    new TextEncoder().encode(thumbprintInput),
717→  );
718→
719→  return base64urlBytes(new Uint8Array(hashBuffer));
720→}
721→
722→async function createDPoPProof(
723→  keyPair: DPoPKeyPair,
724→  method: string,
725→  targetUri: string,
726→): Promise<string> {
727→  const header = {
728→    typ: "dpop+jwt" as const,
729→    alg: "ES256" as const,
730→    jwk: {
731→      kty: keyPair.publicJwk.kty,
732→      crv: keyPair.publicJwk.crv,
733→      x: keyPair.publicJwk.x,
734→      y: keyPair.publicJwk.y,
735→    },
736→  };
737→
738→  const payload = {
739→    jti: crypto.randomUUID(),
740→    htm: method,
741→    htu: targetUri,
742→    iat: Math.floor(Date.now() / 1000),
743→  };
744→
745→  const importedKey = await jose.importJWK(
746→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
747→    "ES256",
748→  );
749→
750→  return await new jose.SignJWT(payload)
751→    .setProtectedHeader(header)
752→    .sign(importedKey);
753→}
754→
755→function base64urlBytes(bytes: Uint8Array): string {
756→  const binary = String.fromCharCode(...bytes);
757→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
758→}
