772→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
773→  return await Promise.race([
774→    callback(),
775→    new Promise<T>((_, reject) => {
776→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
777→    }),
778→  ]);
779→}
