 48→export function buildEmailAndPasswordConfig(): EmailAndPasswordConfig {
 49→  return {
 50→    enabled: true,
 51→    password: {
 52→      hash: (password: string) => Bun.password.hash(password, "argon2id"),
 53→      verify: ({ hash, password }: { hash: string; password: string }) =>
 54→        Bun.password.verify(password, hash),
 55→    },
 56→  };
 57→}
