 66→  ];
 67→
 68→  const signupGuard = buildSignupGuard(config.selfHosted);
 69→
 70→  return betterAuth({
 71→    secret: config.betterAuthSecret,
 72→    baseURL: config.betterAuthUrl,
 73→    basePath: "/api/auth",
 74→    database: surrealdbAdapter(surreal),
 75→    ...(signupGuard ? { databaseHooks: signupGuard } : {}),
 76→    user: {
 77→      modelName: "person",
 78→      fields: {
 79→        email: "contact_email",
 80→        emailVerified: "email_verified",
 81→        createdAt: "created_at",
 82→        updatedAt: "updated_at",
 83→      },
 84→    },
 85→    session: {
 86→      storeSessionInDatabase: true,
 87→      fields: {
 88→        userId: "person_id",
 89→        expiresAt: "expires_at",
 90→        ipAddress: "ip_address",
 91→        userAgent: "user_agent",
 92→        createdAt: "created_at",
 93→        updatedAt: "updated_at",
 94→      },
 95→    },
 96→    account: {
 97→      fields: {
 98→        userId: "person_id",
 99→        accountId: "account_id",
100→        providerId: "provider_id",
101→        accessToken: "access_token",
102→        refreshToken: "refresh_token",
103→        accessTokenExpiresAt: "access_token_expires_at",
104→        refreshTokenExpiresAt: "refresh_token_expires_at",
105→        idToken: "id_token",
106→        createdAt: "created_at",
107→        updatedAt: "updated_at",
108→      },
109→    },
110→    verification: {
111→      fields: {
112→        expiresAt: "expires_at",
113→        createdAt: "created_at",
114→        updatedAt: "updated_at",
115→      },
116→    },
117→    emailAndPassword: buildEmailAndPasswordConfig(),
118→    socialProviders: {
119→      github: {
120→        clientId: config.githubClientId,
121→        clientSecret: config.githubClientSecret,
122→      },
123→    },
124→    plugins: [
125→      jwt(),
126→      oauthProvider({
127→        loginPage: "/sign-in",
128→        consentPage: "/consent",
129→        scopes: allScopes,
130→        validAudiences: [config.betterAuthUrl],
131→        allowDynamicClientRegistration: true,
132→        allowUnauthenticatedClientRegistration: true,
133→        accessTokenExpiresIn: 3600,
134→        refreshTokenExpiresIn: 2592000,
135→        customAccessTokenClaims: async ({ user }) => {
136→          if (!user) return {};
137→          const [memberRows] = await surreal.query<
138→            [Array<{ workspace_id: RecordId<"workspace", string>; workspace_name: string }>]
139→          >(
140→            `SELECT out.id AS workspace_id, out.name AS workspace_name
141→             FROM member_of
142→             WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person)
143→             LIMIT 1;`,
144→            { person: new RecordId("person", user.id) },
145→          );
146→
147→          if (memberRows.length === 0) {
148→            return {};
149→          }
150→
151→          return {
152→            "urn:brain:workspace": memberRows[0].workspace_id.id as string,
153→            "urn:brain:workspace_name": memberRows[0].workspace_name,
154→            "urn:brain:agent_type": "code_agent",
155→          };
156→        },
157→      }),
158→    ],
159→  });
160→}
